#!/usr/bin/env python
"""
Bootstrap: Physics-Driven Ring Enumerator + Demand Grammar
  - 40 ring systems (1-4 fused rings, all fusion patterns)
  - Positional decoration enumeration
  - 22 decorator fragments (HBD, HBA, boronic, linker)
  - Physics demand vector (sugar -> receptor requirements)
  - Grammar-driven generation (demand -> scaffold filter -> enumerate -> score)
  - 39 tests, zero regression

Requires: glycan module + core/pareto.py + RDKit
Usage: python bootstrap_ring_grammar.py
"""
import base64, os, sys

if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)

FILES = {
    'glycan/ring_enumerator.py': '',
    'glycan/demand_grammar.py': '',
    'glycan/tests/test_ring_grammar.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")

print()
print("Done. Run:")
print("  python -m pytest glycan/tests/test_ring_grammar.py -v")